 28→const ScoreRing: React.FC<{ score: number; size?: number }> = ({ score, size = 120 }) => {
 29→  const radius = (size - 12) / 2;
 30→  const circumference = 2 * Math.PI * radius;
 31→  const offset = circumference - (score / 100) * circumference;
 32→  const color = score >= 70 ? '#22c55e' : score >= 40 ? '#f59e0b' : '#ef4444';
 33→
 34→  return (
 35→    <div className="relative" style={{ width: size, height: size }}>
 36→      <svg width={size} height={size} className="transform -rotate-90">
 37→        <circle cx={size / 2} cy={size / 2} r={radius} stroke="rgba(255,255,255,0.05)" strokeWidth="8" fill="none" />
 38→        <circle cx={size / 2} cy={size / 2} r={radius} stroke={color} strokeWidth="8" fill="none"
 39→          strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={offset}
 40→          style={{ transition: 'stroke-dashoffset 1s ease-out' }} />
 41→      </svg>
 42→      <div className="absolute inset-0 flex flex-col items-center justify-center">
 43→        <span className="text-3xl font-bold text-white">{score}</span>
 44→        <span className="text-[10px] text-gray-500 uppercase tracking-wider">/100</span>
 45→      </div>
 46→    </div>
 47→  );
