const fs = require('fs');

// ── Step 1: Add sentimentNeutral key to all locale files ──
const localeFiles = {
  'i18n/locales/fr.ts': "sentimentNeutral: 'Neutre',",
  'i18n/locales/en.ts': "sentimentNeutral: 'Neutral',",
  'i18n/locales/es.ts': "sentimentNeutral: 'Neutro',",
};

for (const [file, line] of Object.entries(localeFiles)) {
  let content = fs.readFileSync(file, 'utf8');
  // Insert after sentimentMixed line
  const anchor = content.includes("sentimentMixed: 'Mixte'") ? "sentimentMixed: 'Mixte',"
    : content.includes("sentimentMixed: 'Mixed'") ? "sentimentMixed: 'Mixed',"
    : content.includes("sentimentMixed: 'Mixto'") ? "sentimentMixed: 'Mixto',"
    : null;
  if (anchor && !content.includes('sentimentNeutral')) {
    content = content.replace(anchor, anchor + '\n    ' + line);
    fs.writeFileSync(file, content, 'utf8');
    console.log(`Added sentimentNeutral to ${file}`);
  } else if (content.includes('sentimentNeutral')) {
    console.log(`sentimentNeutral already exists in ${file}`);
  } else {
    console.log(`WARNING: Could not find anchor in ${file}`);
  }
}

